class TLB:
    def __init__(self, size):
        self.size = size
        self.entries = {}  # page_num -> frame_num

    def lookup(self, page_num):
        if page_num in self.entries:
            return self.entries[page_num], True  # Hit
        return None, False  # Miss

    def update(self, page_num, frame_num):
        if len(self.entries) >= self.size:
            # Simple FIFO eviction for demo
            first_key = next(iter(self.entries))
            del self.entries[first_key]
        self.entries[page_num] = frame_num

def translate_address(virtual_addr, tlb, page_table):
    page_num = virtual_addr // 4096  # Assuming 4KB pages
    offset = virtual_addr % 4096

    # Try TLB first
    frame_num, hit = tlb.lookup(page_num)

    if not hit:
        # TLB miss - check page table
        if page_num in page_table:
            frame_num = page_table[page_num]
            tlb.update(page_num, frame_num)
        else:
            raise PageFaultException()

    physical_addr = frame_num * 4096 + offset
    return physical_addr, hit

#include <stdio.h>
#include <stdint.h>

// Assume: 32-bit address, 4KB pages
// Page offset: 12 bits
// Each page table fits in one page: 1024 entries = 4KB
// Level 1: 10 bits, Level 2: 10 bits, Offset: 12 bits

#define PAGE_OFFSET_BITS 12
#define PTE_BITS 10
#define PAGE_SIZE 4096

typedef struct {
    uint32_t valid:1;
    uint32_t frame_num:20;
    uint32_t protection:3;
} PTE;

uint32_t translate_address(uint32_t virtual_addr, PTE* level1_table, PTE** level2_tables) {
    // Extract page numbers
    uint32_t offset = virtual_addr & (PAGE_SIZE - 1);
    uint32_t page2 = (virtual_addr >> PAGE_OFFSET_BITS) & ((1 << PTE_BITS) - 1);
    uint32_t page1 = (virtual_addr >> (PAGE_OFFSET_BITS + PTE_BITS)) & ((1 << PTE_BITS) - 1);

    // Check level 1 entry
    PTE l1_entry = level1_table[page1];
    if (!l1_entry.valid) {
        printf("Page Fault!\n");
        return 0xFFFFFFFF;
    }

    // Get level 2 page table
    PTE* l2_table = level2_tables[l1_entry.frame_num];

    // Check level 2 entry
    PTE l2_entry = l2_table[page2];
    if (!l2_entry.valid) {
        printf("Page Fault!\n");
        return 0xFFFFFFFF;
    }

    // Construct physical address
    uint32_t physical_addr = (l2_entry.frame_num << PAGE_OFFSET_BITS) | offset;
    return physical_addr;
}
